import React from "react";
import PropTypes from "prop-types";
import Query from "../../components/query/finder__query";
import DefaultFilters from "../../components/filters/finder__filtersmobile";
import CityFilters from "../../components/filters/city/finder__filtersmobile-city";
import CitySportsFilters from "../../components/filters/city-sport/finder__filtersmobile-citySports";
import Results from "../../components/results/finder__results";
import useLogicWrapper from "../../logic/logic";
import useHasMounted from "../../logic/has-mounted";

import type { FinderProps } from "../../types/forms/finder";

function Finder(props: FinderProps) {
  const hasMounted = useHasMounted();
  // Empty result set used until the first real response comes back from useLogicWrapper.
  const intialResults = Object.freeze({
          bestBets: [],
          extraSearches: {},
          facets: [],
          results: [],
          spell: null,
          summary: {
            currEnd: 0,
            currStart: 0,
            numRanks: 0,
            totalMatching: 0,
          },
        });

// Use server-provided query params during SSR, then switch to the browser URL after hydration.
  const initialQuery = hasMounted 
  ? new URLSearchParams(window.location.search) 
  : props.initialQuery || {};

  const {
    query,
    funnelbackResponse,
    updating,
    updater,
    clear,
    matrixState,
    summaryHeadingRef,
  } = useLogicWrapper(
    props.config,
    props.initialResults ?? intialResults,
    initialQuery,
    props.element,
  );
  
  const sharedProps = {
  config: props.config,
  query,
  response: funnelbackResponse,
  update: updater,
  updating,
  summariseAs: props.config.summariseAs,
  clear,
  mobile: true,
  hasMounted,
  matrixState,
};

  const finderMain = (
    <>
      {/* Only render a filters panel when the config supplies facet labels to filter by. */}
      {props.config.facetLabels && props.config.facetLabels.length > 0 && (
        <>
          {/* Each site has its own filters UI/behaviour; fall back to the default for anything else. */}
          {props.config.site === 'city' && <CityFilters {...sharedProps} />}
          {props.config.site === 'citysport' && <CitySportsFilters {...sharedProps} />}
          {props.config.site !== 'city' && props.config.site !== 'citysport' && <DefaultFilters {...sharedProps} />}
        </>
      )}

      <Results
        clear={clear}
        config={props.config}
        query={query}
        response={funnelbackResponse}
        summariseAs={props.config.summariseAs}
        type={props.config.resultCard}
        update={updater}
        updating={updating}
        summaryHeadingRef={summaryHeadingRef}
        matrixState={matrixState}
      />
    </>
  );

  const QueryInput = (
    <Query
      config={props.config}
      query={query}
      update={updater}
      updating={updating}
    />
  );

  // If the site is bayes, we want to render the query input in the top section

  const topSectionQueryInput =
    props.config.queryInputConfig &&
    props.config.queryInputConfig.showQueryInTopSection ? (
      <div className="v26-finder__top">
        <div className="container">{QueryInput}</div>
      </div>
    ) : null;

  return (
    <form
      className="v26-finder"
      method="GET"
      // Submission is handled entirely via updater/state, not a real GET navigation.
      onSubmit={(e) => {
        e.preventDefault();
      }}
    >
      {props.config.site && props.config.site === "bayes" ? (
        // Bayes layout: query input lives in its own top section above the main grid.
        <>
          {topSectionQueryInput}
          <div className="v26-finder__main">
            <div className="container">
              <div className="grid">{finderMain}</div>
            </div>
          </div>
        </>
      ) : (
        // Default layout: query input sits directly above the results/filters.
        <>
        {QueryInput}
        {props.config.site && props.config.site === "city" ? (
          <div className="v26-finder__main">{finderMain}</div>
        ) : (
          finderMain
        )}
      </>
      )}
    </form>
  );
}

Finder.propTypes = {
  config: PropTypes.object.isRequired,
  element: PropTypes.object,
  initialQuery: PropTypes.object,
  initialResults: PropTypes.object,
};

export default Finder;
