import PropTypes from "prop-types";
import React from "react";
import formatLabel from "../results/formatLabel";
import { uppercaseFirstLetterLowercaseRest } from "../../util";
import type { ResultsCourse } from "../../types/cards/card";

/**
 * Render a Funnelback result as a course card.
 *
 * @param {object} props React props.
 * @return {object} - React component.
 */

const externalSiteUrl = ["www.citystgeorges.ac.uk"];

//classname generation for location and school
const generateAcronym = (text: string): string => {
  const normalizedText = text.trim().toLowerCase();
  switch (normalizedText) {
    case "school of policy and global affairs":
      return "spga";
    case "the city law school":
      return "cls";
    case "school of science and technology":
      return "stt";
    case "school of health and medical sciences":
      return "shms";
    case "school of communication and creativity":
      return "scc";
    case "bayes business school":
      return "bayes";
  }
  return text
};

const sortLocations = (locations: string[]): string[] =>
  [...locations].sort((a, b) => {
    const normalizedA = a.trim().toLowerCase();
    const normalizedB = b.trim().toLowerCase();
    if (normalizedA === normalizedB) return 0;
    if (normalizedA === "online") return 1;
    if (normalizedB === "online") return -1;
    return normalizedA.localeCompare(normalizedB);
  });

function Finder__Results__Coursev26(props: ResultsCourse) {
  console.log('TEST')
  let locationClassName = null,
    schoolClassName = null;
  if (props.details.listMetadata?.location) {
    if(props.details.listMetadata.location.length > 1) {
      locationClassName = `v26-course__location-icon--${sortLocations(props.details.listMetadata.location).map((l) => l.trim().toLowerCase().split(' ')[0]).join('-')}`;
    }else{  
    const location = String(props.details.listMetadata.location).toLowerCase().trim();
    console.log(location);
     switch (location) {
      case "online":
        locationClassName = "v26-course__location-icon--online";
        break;
      case "clerkenwell campus":
        locationClassName = "v26-course__location-icon--clerkenwell";
        break;
      case "tooting campus":
        locationClassName = "v26-course__location-icon--tooting";
        break;
      case "moorgate campus":
        locationClassName = "v26-course__location-icon--moorgate";
        break;
      }
    }
  }
  if (props.details.listMetadata?.school) {
    if(props.details.listMetadata?.school.length > 1) {
      schoolClassName = `v26-course__school-icon--${[...props.details.listMetadata.school].sort((a, b) => a.localeCompare(b)).map((s) => generateAcronym(s)).join('-').toLowerCase()}`;
    }else{
      const school = String(props.details.listMetadata.school[0]).toLowerCase().trim();
      switch (school) {
        case "school of policy and global affairs":
          schoolClassName = "v26-course__school-icon--spga";
          break;
        case "the city law school":
          schoolClassName = "v26-course__school-icon--cls";
          break;
        case "school of science and technology":
          schoolClassName = "v26-course__school-icon--stt";
          break;
        case "bayes business school":
          schoolClassName = "v26-course__school-icon--bayes";
          break;
        case "school of health and medical sciences":
          schoolClassName = "v26-course__school-icon--shms";
          break;
        case "school of communication and creativity":
          schoolClassName = "v26-course__school-icon--scc";
          break;
      }
    }
    
  } 
  const subtitle =
      (props.details.listMetadata?.type?.[0]) ||
      (props.details.listMetadata?.level?.[0]) ||
      null,
    duration = props.details.listMetadata?.duration && (
        <p className="card__tag">
          <span>Duration:</span>{" "}
          <span><strong>{props.details.listMetadata.duration[0]}</strong></span>
        </p>
      ),
    method = props.details.listMetadata?.method &&
      props.details.listMetadata?.level?.[0] !==
        "Short courses and professional development" &&
      ((props.query.facets?.method) ||
        props.query.query.indexOf(props.details.listMetadata.method[0]) >= 0 ||
        props.details.listMetadata.method[0].indexOf("Online") >= 0) && (
        <p className="card__tag">
          <span>
            Method
            {props.details.listMetadata.method.length > 1 && "s"} of study:
          </span>{" "}
          <span><strong>
            {uppercaseFirstLetterLowercaseRest(
              Array.from(new Set(props.details.listMetadata.method)).join("|"), // Remove any duplicates & format
            )
              .split("|")
              .join(", ")}
          </strong></span>
        </p>
      ),
    location =
      props.details.listMetadata?.location &&
      String(props.details.listMetadata.location).toLowerCase() !== "tooting"
      && (
            <p className="card__tag">
              <span
                className="icon"
                aria-hidden="true"
              >
                <span className={`v26-course__location-icon ${locationClassName}`} aria-hidden="true" />  
              </span>{" "}
              <span>Location:</span>{" "}
              <span>
                {/* Avoid duplication of 'Online' location label if location and method of study are both online */}
                <strong>
                    {sortLocations(props.details.listMetadata.location).join("|") ===
                    "Online|Online"
                    ? "Online"
                    : sortLocations(props.details.listMetadata.location).join(", ")}
                </strong>
              </span>
            </p>
          ),
    school = props.details.listMetadata?.school && (
        <p className="card__tag">
          <span
            className="icon"
            aria-hidden="true"
          >
            <span className={`v26-course__school-icon ${schoolClassName}`} aria-hidden="true" />
          </span>{" "}
          <span>School:</span>{" "}
          <span>
            <strong>
                {[...props.details.listMetadata.school].sort((a, b) => a.localeCompare(b)).map((e, i) =>
                i === 0 ? (
                    <React.Fragment key={i}>{e.replace("and", "&")}</React.Fragment>
                ) : (
                    <React.Fragment key={i}>| {e}</React.Fragment>
                ),
                )}
            </strong>
          </span>
        </p>
      ),
    // City St George's label temporarily in place according to branding guidelines
    stGeorgesLabel =
      props.details.listMetadata &&
      String(props.details.listMetadata.location).toLowerCase() ===
        "tooting" ? (
        <div className="card__label card--course__label--stgeorges">
          <p>
            <span
              className="fas fa-fw fa-map-marker-alt icon"
              aria-hidden="true"
            />{" "}
            Tooting Campus
          </p>
        </div>
      ) : null,
    // City and Business School use different metadata values; check for both
    clearing = props.details.listMetadata?.clearing &&
      ["Clearing", "clearing"].includes(props.details.listMetadata.clearing[0]) && (
        <div className="card__label card--v26-course__label--clearing">
          <p>Clearing</p>
        </div>
      ),
    external = !externalSiteUrl.some(
      (s) => props.details.indexUrl && props.details.indexUrl.indexOf(s) >= 0,
    ) ? (
      <>
        {" "}
        <span
          className="fas fa-sharp fa-external-link icon"
          aria-label="(external link)"
        ></span>
      </>
    ) : null,
    courseCode =
      props.details.listMetadata &&
      props.details.listMetadata.code &&
      ([
        "Undergraduate degree",
        "Foundation course",
        "Postgraduate taught degree",
      ].some(
        (s) =>
          props.details.listMetadata &&
          props.details.listMetadata.level &&
          props.details.listMetadata.level.indexOf(s) >= 0,
      ) ||
        props.query.query.indexOf(props.details.listMetadata.code[0]) >= 0) ? (
        <p className="card__tag">
          <span>
            UCAS code
            {props.details.listMetadata.code.length > 1 && 's'}:
          </span>{' '}
          <span><strong>{props.details.listMetadata.code.join('/')}</strong></span>
        </p>
      ) : null,
      cardHeading = props.query.query || props.details.title ? (<h3 className="card__heading">
                        <a href={props.details.liveUrl}>
                            {props.query.query
                                ? formatLabel(props.details.title, props.query.query)
                                : props.details.title}
                            {external}
                        </a>
                    </h3>) : null;

  // compute entryYears separately; ensure we don't rely on potentially undefined metadata
  let entryYears = null;
  const _entryyears = props.details.listMetadata?.entryyears;
  if (_entryyears && _entryyears.length > 0) {
    entryYears = (
      <p className="card__tag">
        <span>
          Year{_entryyears.length > 1 && 's'} of entry:
        </span>{' '}
        <span>
          {_entryyears.map((year, idx) => {
            const baseUrl = props.details.liveUrl;
            const href = idx > 0 ? `${baseUrl}/${year}` : baseUrl;
            return (
              <React.Fragment key={year}>
                <strong><a href={href}>{year}</a></strong>
                {idx < _entryyears.length - 1 ? ', ' : ''}
              </React.Fragment>
            );
          })}
        </span>
      </p>
    );
  }

  const description = props.details?.listMetadata?.c?.[0] && (
        <p className="card__description">
          {props.query.query
            ? formatLabel(props.details.listMetadata.c[0], props.query.query)
            : props.details.listMetadata.c[0]}
        </p>
      );

  return (
    <li className="card card--v26-course">
        <div className="wrapper--card__label__details">
          <div className="card__details__text">
            {clearing ? (
              <div className={"card__heading-wrapper"}>
                {clearing}
                {cardHeading}
              </div>
              ) : (
              cardHeading
              )
            }
            
            <p className="card__type">
              {props.query.query && subtitle
                ? formatLabel(subtitle, props.query.query)
                : subtitle && subtitle}
            </p>
            {description}
            {stGeorgesLabel}
            {duration || courseCode ? (
                <div className="card--v26-course__duration-and-code">{duration}{courseCode}</div>
                ) : null}
            {entryYears}
            {method}
            {location || school ? (<div className={'card--v26-course__location'}>{school}{location}</div>) : null}
          </div>
        </div>
    </li>
  );
}

Finder__Results__Coursev26.propTypes = {
  details: PropTypes.object,
  query: PropTypes.object,
};

export default Finder__Results__Coursev26;
