import React from "react";
import PropTypes from "prop-types";
import SelectFilter from "../finder__select";
import MultiCheckbox from "../finder__multiCheckbox";
import EventSelectFilter from "../finder__eventSelect";
import CheckboxFilter from "../finder__checkbox";
import ParamCheckBox from "../finder__paramCheckbox";
import EventCheckBox from "../finder__eventCheckbox";
import HiddenInput from "../finder__hiddenInput";
import TagFilter from "../finder__tag";
import Reset from "../finder__reset";
import Sort from "../finder__sort";
import { gaEvent } from "../../../util";
import type { Filters } from "../../../types/filters/filters";
import type { FacetDetails } from "../../../types/facet";

/**
 * Predicate for whether a facet should be displayed, if it's dependent on
 * another facet being set.
 *
 * @param {object} facet The facet to potentially display.
 * @param {object} facetMap The facets currently set on the query.
 * @return {bool} - Has any dependency been met
 */
function dependencyMet(
  facet: FacetDetails,
  facetMap: { [key: string]: string | string[] },
) {
  const dependency = facet.dependency;
  if (!dependency) return true;

  if (typeof dependency === "string") {
    const val = facetMap[dependency];
    if (!val) return false;
    
    return Array.isArray(val) ? val.length > 0 : val !== "";
  }

  return Object.keys(dependency).some((key) => {
    const val = facetMap[key];
    if (!val) return false;

    const expectedValues = new Set(
      dependency[key].map((v: string) => v.toLowerCase()),
    );
    return Array.isArray(val)
      ? val.some((v) => expectedValues.has(v.toLowerCase()))
      : expectedValues.has(val.toLowerCase());
  });
}

/**
 * Component to update facet values in the query.
 *
 * @param {object} props React props.
 * @returns {object} - React component.
 */
function Finder__Filters(props: Filters) {
  const totalMatching = props.response?.summary?.fullyMatching;
  const clearFiltersDesktop =
      !props.updating && Object.keys(props.query.facets).length > 0 ? (
        <div className="v26-finder__filters__reset v26-finder__filters__reset--desktop">
          <Reset
            clear={props.clear}
            resetSort={false}
            matrixState={props.matrixState}
            site={props.config.site || "city"} // Ensure site is defined
          />
        </div>
      ) : null,
    clearFiltersMobile =
      (!props.updating && Object.keys(props.query.facets).length > 0) ||
      props.query.sortType !== props.config.sort[0].type ? (
        <Reset
          clear={props.clear}
          resetSort={true}
          matrixState={props.matrixState}
          site={props.config.site || "city"} // Ensure site is defined
        />
      ) : null;

  const sort =
    !props.matrixState &&
    props.config.sort.length > 1 &&
    props.config.displaySort &&
    totalMatching ? (
      <div className="wrapper--v26-finder__select--sort--mobile">
        <Sort
          key={props.mobile ? "sort-mobile" : "sort-desktop"}
          config={props.config}
          query={props.query}
          update={props.update}
        />
      </div>
    ) : null;

  const submitSSR = props.matrixState ? (
    <div className="v26-finder__filter__submit">
      <button type="submit" className="v26-finder__query__submit v26-finder__submit">
        <span
          className="fal fa-sharp fa-search finder__query__submit__icon"
          aria-hidden="true"
        />{" "}
        <span className="v26-finder__query__submit__text">Find</span>
      </button>
    </div>
  ) : null;

  return (
    <div className="v26-finder__filters">
      <h2 className="v26-finder__filters__heading">
        <span className="v26-finder__filters__heading__text">
          <span className="far fa-sharp fa-sliders-h icon" aria-hidden="true" />{" "}
          {`Filter ${props.config.summariseAs?.plural}`}
        </span>
        {clearFiltersMobile}
      </h2>

      <fieldset>
        {!props.hasMounted && props.query.fixedParameters?.map((param) => (
          <HiddenInput
            key={param.name}
            name={param.name}
            value={param.value}
          />
        ))}
        <div className="wrapper--v26-finder_filters--filters">
          {props.config.facetLabels?.map((facet) => {
              if (dependencyMet(facet, props.query.facets)) {
                switch (facet.type) {
                  case 'multiCheckbox':
                    return (<MultiCheckbox
                        key={facet.meta}
                            facet={facet}
                            query={props.query}
                            responseFacet={
                                props.response?.facets?.filter(
                                          (funnelbackFacet) =>
                                              funnelbackFacet.name.toLowerCase() ===
                                              facet.funnelbackName.toLowerCase()
                                      ) ?? []
                            }
                            update={props.update}
                            dependencies={props.config.facetLabels?.filter(
                                (candidate) => candidate.dependency === facet.meta,
                              )}
                            mobile={props.mobile}
                            matrixState={props.matrixState}
                    />);
                  case "eventCheckBox":
                    return (
                      <EventCheckBox
                        key={facet.meta}
                        facet={facet}
                        query={props.query}
                        update={props.update}
                        pastEventsResponse={
                          props.response?.extraSearches?.past?.response
                        }
                        matrixState={props.matrixState}
                      />
                    );
                  case "paramCheckBox":
                    return (
                      <ParamCheckBox
                        key={facet.meta}
                        facet={facet}
                        query={props.query}
                        update={props.update}
                        pastEventsResponse={
                          props.response?.extraSearches?.past?.response
                        }
                      />
                    );
                  case "eventSelect":
                    return (
                      <EventSelectFilter
                        key={facet.meta}
                        facet={facet}
                        query={props.query}
                        responseFacet={
                          props.response?.facets?.filter(
                                (funnelbackFacet) =>
                                  funnelbackFacet.name === facet.funnelbackName,
                              ) ?? []
                        }
                        update={props.update}
                        dependencies={
                          props.config.facetLabels?.filter(
                            (candidate) => candidate.dependency === facet.meta,
                          )
                        }
                        mobile={props.mobile}
                      />
                    );
                  case "select":
                    return (
                      <SelectFilter
                        key={facet.meta}
                        facet={facet}
                        query={props.query}
                        responseFacet={
                          props.response?.facets?.filter(
                                (funnelbackFacet) =>
                                  funnelbackFacet.name === facet.funnelbackName,
                              ) ?? []
                        }
                        update={props.update}
                        dependencies={
                          props.config.facetLabels?.filter(
                            (candidate) => candidate.dependency === facet.meta,
                          )
                        }
                        mobile={props.mobile}
                      />
                    );
                  case "checkbox":
                    return (
                      <CheckboxFilter
                        key={facet.meta}
                        facet={facet}
                        query={props.query}
                        responseFacet={
                          props.response?.facets?.filter(
                                (funnelbackFacet) =>
                                  funnelbackFacet.name === facet.funnelbackName,
                              ) ?? []
                        }
                        update={props.update}
                        dependencies={
                          props.config.facetLabels?.filter(
                            (candidate) => candidate.dependency === facet.meta,
                          )
                        }
                        mobile={props.mobile}
                      />
                    );
                  case "tag":
                    return (
                      <TagFilter
                        key={facet.meta}
                        facet={facet}
                        query={props.query}
                        responseFacet={
                          props.response?.facets?.filter(
                                (funnelbackFacet) =>
                                  funnelbackFacet.name === facet.funnelbackName,
                              ) ?? []
                        }
                        update={props.update}
                        dependencies={
                          props.config.facetLabels?.filter(
                            (candidate) => candidate.dependency === facet.meta,
                          )
                        }
                        matrixState={props.matrixState}
                      />
                    );
                  default:
                    gaEvent(
                      "jsError",
                      "JavaScript error",
                      "finder__filters()",
                      "Unknown filter type in finder__filters.js",
                      0,
                      true,
                    );
                }
              } else {
                return null;
              }
            })}
          <p className="v26-finder__filters__nofilters">
            No filters are valid for the current query.
          </p>
          {clearFiltersDesktop}
          {sort}
          {submitSSR}
        </div>
      </fieldset>
    </div>
  );
}

Finder__Filters.propTypes = {
  config: PropTypes.object,
  query: PropTypes.object,
  response: PropTypes.object,
  update: PropTypes.object,
  clear: PropTypes.func,
  mobile: PropTypes.bool,
  hasMounted: PropTypes.bool,
  matrixState: PropTypes.bool,
  updating: PropTypes.bool,
};

export default Finder__Filters;
