/**
 * Utility Helpers
 * @module util
 * A collection of reusable helper functions used throughout the application.
 *
 * These utilities support both browser and server environments. Because this
 * project may execute code in a server-side rendering (SSR) context, any
 * access to browser-specific APIs such as `window` or `document` must be
 * guarded to prevent runtime errors.
 *
 * To ensure safe execution:
 *   - Browser globals are accessed through helper functions like `getWindow()`
 *     and `getDocument()`.
 *   - Functions that require a DOM environment explicitly validate that
 *     `document` is available before executing.
 *   - Browser-only features degrade gracefully when running on the server.
 *
 * This allows the module to be safely imported in Node.js while still
 * providing full functionality when executed in the browser.
 *
 * Categories of utilities included here:
 *   - DOM manipulation helpers
 *   - browser feature detection
 *   - query parameter parsing
 *   - analytics helpers
 *   - formatting utilities
 *   - data transformation utilities
 *
 * Notes:
 *   Some functions intentionally no-op or return fallback values when
 *   executed server-side, as certain browser APIs simply do not exist
 *   outside the client environment.
 */

import axios, { AxiosRequestConfig } from "axios";
import React from "react";

import type {
  Response,
  ExtraSearches,
  FunnelbackRawResponse,
} from "./types/FBresponse";

function hasWindow(): boolean {
  return typeof window !== "undefined";
}

function hasDocument(): boolean {
  return typeof document !== "undefined";
}

function getWindow(): Window | null {
  return hasWindow() ? window : null;
}

function getDocument(): Document | null {
  return hasDocument() ? document : null;
}

function requireDocument(functionName: string): Document {
  const doc = getDocument();

  if (!doc) {
    throw new Error(`${functionName} can only be used in a browser environment.`);
  }

  return doc;
}

export function toBool(s: string): boolean {
  return s === "true";
}

const partialMatchFn = (m: string) => (s: string) => s.indexOf(m) < 0;
const fullMatchFn = (m: string) => (s: string) => s !== m;

export function removeClass(
  elem: HTMLElement,
  className: string,
  removePartials = false,
): void {
  const matchFn = removePartials
    ? partialMatchFn(className)
    : fullMatchFn(className);

  elem.className = elem.className
    .split(/\s+/)
    .filter((s) => matchFn(s))
    .join(" ");
}

export function reduceMotion(): boolean {
  const win = getWindow();
  const reducedMotionQuery = win
    ? win.matchMedia("(prefers-reduced-motion: reduce)")
    : null;

  return Boolean(reducedMotionQuery?.matches);
}

export function isVisible(elem: HTMLElement): boolean {
  return elem.offsetHeight !== 0 && elem.offsetWidth !== 0;
}

export function verticallyInWindow(elem: HTMLElement): boolean {
  const win = getWindow();
  if (!win) return false;

  const rect = elem.getBoundingClientRect();
  return rect.top >= 0 && rect.top <= win.innerHeight;
}

export function parametersToObject(
  parameterString: string,
): Record<string, string> {
  const parameters: Record<string, string> = {};

  parameterString
    .substring(1)
    .split("&")
    .filter(Boolean)
    .forEach((parameter) => {
      const [k, v = ""] = parameter.split("=");
      parameters[k] = v;
    });

  return parameters;
}

export function objectToParameters(
  parameterObj: Record<string, string>,
): string {
  const keys = Object.keys(parameterObj);

  if (keys.length > 0) {
    return (
      "?" +
      keys
        .map((key) => `${key}=${encodeURIComponent(parameterObj[key])}`)
        .join("&")
    );
  }

  return "";
}

declare global {
  interface Window {
    dataLayer?: unknown[];
  }
}

export function gaEvent(
  event: string,
  eventCategory: string,
  eventAction: string,
  eventLabel?: string,
  eventValue?: number,
  nonInteractionHit?: boolean,
): void {
  const win = getWindow();
  if (!win) return;

  win.dataLayer = win.dataLayer || [];
  win.dataLayer.push({
    event,
    eventCategory,
    eventAction,
    eventLabel,
    eventValue,
    nonInteractionHit,
  });
}

export function appendAll(elem: HTMLElement, children: HTMLElement[]): void {
  children.forEach((child) => elem.appendChild(child));
}

export function numberFromString(value: string): string {
  return value.replace(/\D/g, "");
}

export function isMobile(screen = 432): boolean {
  const win = getWindow();
  if (!win) return false;

  return win.innerWidth < screen;
}

export function toArray(
  obj: HTMLCollection | NodeListOf<HTMLElement>,
): HTMLElement[] {
  return Array.from(obj) as HTMLElement[];
}

export function detectIE(): number | false {
  const win = getWindow();
  if (!win) return false;

  const ua = win.navigator.userAgent;

  const msie = ua.indexOf("MSIE ");
  if (msie > 0) {
    return parseInt(ua.substring(msie + 5, ua.indexOf(".", msie)), 10);
  }

  const trident = ua.indexOf("Trident/");
  if (trident > 0) {
    const rv = ua.indexOf("rv:");
    return parseInt(ua.substring(rv + 3, ua.indexOf(".", rv)), 10);
  }

  const edge = ua.indexOf("Edge/");
  if (edge > 0) {
    return parseInt(ua.substring(edge + 5, ua.indexOf(".", edge)), 10);
  }

  return false;
}

type IntersectionObserverEntryConstructorLike = {
  prototype: {
    intersectionRatio?: unknown;
  };
};

function hasIntersectionRatioOnIntersectionObserverEntry(
  maybeEntry: unknown,
): maybeEntry is IntersectionObserverEntryConstructorLike {
  if (!maybeEntry || typeof maybeEntry !== "function") return false;

  const { prototype } = maybeEntry as IntersectionObserverEntryConstructorLike;
  return !!prototype && typeof prototype === "object" && "intersectionRatio" in prototype;
}

export function checkIntersectionObserver(): boolean {
  const win = getWindow();
  if (!win) return false;

  const maybeEntry = (win as unknown as { IntersectionObserverEntry?: unknown })
    .IntersectionObserverEntry;

  return (
    "IntersectionObserver" in win &&
    hasIntersectionRatioOnIntersectionObserverEntry(maybeEntry)
  );
}

interface Attribute {
  label: string;
  val: string;
}

export function uppercaseFirstLetterLowercaseRest(s: string): string {
  return s.charAt(0).toUpperCase() + s.slice(1).toLowerCase();
}

export function axiosRequest<T = unknown>(
  config: AxiosRequestConfig,
): Promise<T | undefined> {
  return axios(config)
    .then((response) => {
      if (response.status === 200) return response.data;
      throw new Error(`Bad response: ${response.status}`);
    })
    .catch((e: unknown) => {
      if (isRequestCanceled(e)) {
        throw e;
      }

      const error = e as Error;
      const locationLabel = hasWindow() ? String(window.location) : "server";

      gaEvent(
        "jsError",
        "JavaScript error",
        error.message || "Unknown error",
        `axiosRequest (${locationLabel})`,
        0,
        true,
      );

      return undefined;
    });
}

export function isRequestCanceled(error: unknown): boolean {
  if (axios.isCancel(error)) {
    return true;
  }

  if (!(error instanceof Error)) {
    return false;
  }

  const requestError = error as Error & { code?: string };

  return (
    requestError.name === "AbortError" ||
    requestError.name === "CanceledError" ||
    requestError.code === "ERR_CANCELED"
  );
}

export function formatTime(timeString: string, timeZone?: boolean) {
  const timeDate = new Date(timeString);
  let timeLabel = "";

  if (timeZone) {
    const timeOffset = timeDate.getTimezoneOffset() / -60;
    timeLabel = timeOffset === 0 ? "(GMT)" : "(BST)";
  }

  const hours = timeDate.getHours().toString().padStart(2, "0");
  const minutes = timeDate.getMinutes().toString().padStart(2, "0");

  return (
    <time dateTime={`${hours}:${minutes}`}>
      {hours}:{minutes} {timeLabel}
    </time>
  );
}

function daySuffix(day: number): string {
  const lastDigit = day % 10;
  const lastTwoDigits = day % 100;

  if (lastTwoDigits >= 11 && lastTwoDigits <= 13) return "th";

  switch (lastDigit) {
    case 1:
      return "st";
    case 2:
      return "nd";
    case 3:
      return "rd";
    default:
      return "th";
  }
}

export function formatReactDate(date: Date): React.ReactElement {
  const months = [
    "January",
    "February",
    "March",
    "April",
    "May",
    "June",
    "July",
    "August",
    "September",
    "October",
    "November",
    "December",
  ];

  const days = [
    "Sunday",
    "Monday",
    "Tuesday",
    "Wednesday",
    "Thursday",
    "Friday",
    "Saturday",
  ];

  return (
    <time dateTime={date.toISOString().split("T")[0]}>
      {days[date.getUTCDay()]}, {date.getUTCDate()}
      <sup>{daySuffix(date.getUTCDate())}</sup> {months[date.getUTCMonth()]}{" "}
      {date.getUTCFullYear()}
    </time>
  );
}

export function arraySlicer<T>(arr: T[], len: number): T[][] {
  const newArray: T[][] = [];

  for (let i = 0; i < arr.length; i += len) {
    newArray.push(arr.slice(i, i + len));
  }

  return newArray;
}

export function flattenObj(
  ob: Record<string, unknown>,
): Record<string, string> {
  const result: Record<string, string> = {};

  for (const i in ob) {
    const value = ob[i];

    if (typeof value === "object" && !Array.isArray(value) && value !== null) {
      const temp = flattenObj(value as Record<string, unknown>);

      for (const j in temp) {
        if (i === "parameters") {
          result[`${i}-${j}`] = temp[j];
        } else {
          result[j] = temp[j];
        }
      }

    } else if (Array.isArray(value)) {
      value.forEach((val, index) => {

        // array of objects (your existing case)
        if (typeof val === "object" && val !== null) {
          const objVal = val as { meta?: string; name?: string; value?: string };

          if (i === "fixedFacets" && objVal.meta && objVal.value) {
            result[`${i}-${objVal.meta}`] = objVal.value;
          } else if (objVal.name && objVal.value) {
            result[`${i}-${objVal.name}`] = objVal.value;
          }

        // array of primitives (NEW)
        } else {
          result[`${i}[${index}]`] = String(val);
        }
      });

    } else if (value !== null && value !== undefined) {
      result[i] = String(value);
    }
  }

  return result;
}

export function getVerticalScrollbarWidth(): number {
  const doc = getDocument();
  if (!doc) return 0;

  const scrollDiv = doc.createElement("div");
  scrollDiv.style.cssText =
    "width: 100px; height: 100px; overflow: scroll; position: absolute; top: -9999px;";

  doc.body.appendChild(scrollDiv);
  const scrollbarWidth = scrollDiv.offsetWidth - scrollDiv.clientWidth;
  doc.body.removeChild(scrollDiv);

  doc.documentElement.style.setProperty(
    "--scrollbar-width",
    `${scrollbarWidth}px`,
  );

  return scrollbarWidth;
}

export function enableBodyScroll(): void {
  const doc = getDocument();
  if (!doc) return;

  doc.documentElement.classList.remove("no-scroll");

  const btn = doc.querySelector(".back-to-top");
  if (btn) btn.removeAttribute("hidden");
}

export function disableBodyScroll(): void {
  const doc = getDocument();
  if (!doc) return;

  getVerticalScrollbarWidth();

  const btn = doc.querySelector(".back-to-top");
  if (btn) btn.setAttribute("hidden", "true");

  doc.documentElement.classList.add("no-scroll");
}

export function formatFBResponse(json: FunnelbackRawResponse): Response & {
  extraSearches?: {

    [key: string]: ExtraSearches;
  };
} {
  return {
    query: json.question.originalQuery,
    inputParameters: json.question.inputParameters,
    spell: json.response.resultPacket.spell,
    summary: json.response.resultPacket.resultsSummary,
    bestBets: json.response.curator.exhibits,
    results: json.response.resultPacket.results,
    facets: json.response.facets,
    extraSearches: json.extraSearches,
  };
}

export function decodeHtml(html = ""): string {
  const doc = getDocument();
  if (!doc) return html;

  const txt = doc.createElement("textarea");
  txt.innerHTML = html;
  return txt.value;
}

export function capitalizeFirstLetter(s: string): string {
  return s.replace(/^./, (c) => c.toUpperCase())
}
